1	//! Validation harness. Reads a compact description of a theory's rules on stdin
2	//! and prints the injective fact tags (one `name/arity` per line, sorted).
3	//!
4	//! This binary only *reconstructs* `Rule`/`Fact`/`Term` values so the real
5	//! library function can be exercised on rules parsed from the oracle's own
6	//! normalized rule pretty-print. It carries no injectivity logic.
7	//!
8	//! Input grammar (one token stream per line):
9	//!   RULE                 -- start a new rule
10	//!   P <fact>             -- a premise fact
11	//!   C <fact>             -- a conclusion fact
12	//! where <fact> = [!]name arg1 arg2 ...   (whitespace separated, no inner spaces)
13	//! and a token starting with '~' is a Fresh variable; anything else is treated
14	//! as a non-variable literal (only first-argument freshness / equality matter).
15	
16	use injfacts_clean::ast::{Fact, Rule, SortHint, Term, VarSpec};
17	use injfacts_clean::injective_fact_instances;
18	use std::io::{self, Read};
19	
20	fn token_to_term(tok: &str) -> Term {
21	    if let Some(rest) = tok.strip_prefix('~') {
22	        Term::Var(VarSpec {
23	            name: rest.to_string(),
24	            idx: 0,
25	            sort: SortHint::Fresh,
26	            typ: None,
27	        })
28	    } else {
29	        Term::PubLit(tok.to_string())
30	    }
31	}
32	
33	fn parse_fact(fields: &[&str]) -> Fact {
34	    let raw = fields[0];
35	    let (persistent, name) = match raw.strip_prefix('!') {
36	        Some(n) => (true, n.to_string()),
37	        None => (false, raw.to_string()),
38	    };
39	    let args = fields[1..].iter().map(|t| token_to_term(t)).collect();
40	    Fact {
41	        persistent,
42	        name,
43	        args,
44	        annotations: vec![],
45	    }
46	}
47	
48	fn empty_rule() -> Rule {
49	    Rule {
50	        name: String::new(),
51	        modulo: None,
52	        attributes: vec![],
53	        let_block: vec![],
54	        premises: vec![],
55	        actions: vec![],
56	        conclusions: vec![],
57	        embedded_restrictions: vec![],
58	        variants: vec![],
59	        left_right: None,
60	    }
61	}
62	
63	fn main() {
64	    let mut input = String::new();
65	    io::stdin().read_to_string(&mut input).unwrap();
66	
67	    let mut rules: Vec<Rule> = Vec::new();
68	    let mut cur: Option<Rule> = None;
69	    for line in input.lines() {
70	        let line = line.trim();
71	        if line.is_empty() {
72	            continue;
73	        }
74	        let fields: Vec<&str> = line.split_whitespace().collect();
75	        match fields[0] {
76	            "RULE" => {
77	                if let Some(r) = cur.take() {
78	                    rules.push(r);
79	                }
80	                cur = Some(empty_rule());
81	            }
82	            "P" => {
83	                if let Some(r) = cur.as_mut() {
84	                    r.premises.push(parse_fact(&fields[1..]));
85	                }
86	            }
87	            "C" => {
88	                if let Some(r) = cur.as_mut() {
89	                    r.conclusions.push(parse_fact(&fields[1..]));
90	                }
91	            }
92	            _ => {}
93	        }
94	    }
95	    if let Some(r) = cur.take() {
96	        rules.push(r);
97	    }
98	
99	    let result = injective_fact_instances(&rules);
100	    for (name, arity) in result {
101	        println!("{}/{}", name, arity);
102	    }
103	}
